<template>
    <section>
            <loader :is-visible="isLoading"></loader>
            <tg-list :IsShowAction="true" :showCheckBox="isShowCheckBox" ModuleName="RuleEngine" :listType="['List']"
                :HeaderButtons="listheaderbuttons" :HeaderText="billingRule"
                :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick"
                SubModuleCode="RuleEngine" IdentityColumn="limit_id" :ListData="LimitData" :HeaderData="Headers"
                :callbackfunction="FetchData" v-on:HeaderButtonClick="commonHeaderButtonClick"
                :TotalRecords="TotalRecords" :ListDataCallBackFunction="FetchData" :LegendArray="[]" :SortExp="sortExp"
                :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" v-on:PagerButtonClick="pagerMethod"
                v-on:SortdataButtonClick="sortdata">
                <template v-slot:slotdata="{ data }">
                    <template v-if="data.column.COLUMN_NAME == 'dayLimit'">
                        <span> {{ data.row.dayLimit !== null && data.row.dayLimit !== '' 
                                ? data.row.dayLimit + ' day(s)' 
                                : '-' }}
                        </span>
                    </template>
                </template>
            </tg-list>
        <AddLimit v-if="isAddLimit" :callbackfunction="FetchData" :refCode="refCode" @CloseLimit="CloseLimit"
            :configurationId="this.configurationId" :EditLimitData="EditLimitData" :clientId="clientId">
        </AddLimit>
    </section>
</template>
<script>

import DataService from '../../../services/DataService';
import AddLimit from './AddLimit.vue'
export default {
    components: { AddLimit },
    props: {
        configurationId: {
            type: String,
            default: null
        },
        mode: {
            type: String,
            default: 'Edit'
        },
        isBillingType :{
            type: Boolean,
            required: false
        },
        clientId: {
            type: Number,
            default: false
        },
        billingRule:{
            type : String,
            required : false
        }
    },
    data() {
        return {
            EditLimitData: [],
            isLoading: false,
            refCode: '',
            isAddLimit: false,
            noRecord: true,
            LimitData: [],
            TotalRecords: 0,
            ConfigId: 0,
            LimitId: 0,
            Sort_By: '',
            Sort_Exp: '',
            PageSize: 10,
            PageNumber: 1,
            isShowCheckBox:true,
            Headers: [
                {
                    COLUMN_NAME: "clientLimitName",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('LimitFor'),
                    DISPLAY_ORDER: 1,
                },
                {
                    COLUMN_NAME: "workCode",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('WorkCode'),
                    DISPLAY_ORDER: 2,
                },
                {
                    COLUMN_NAME: "limitValue",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('LimitValue'),
                    DISPLAY_ORDER: 3,
                },
                {
                    COLUMN_NAME: "dayLimit",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('DayLimit'),
                    DISPLAY_ORDER: 4,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    COLUMN_NAME: "alternateWorkCode",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('AlternateWorkCode'),
                    DISPLAY_ORDER: 5,
                },

                {
                    COLUMN_NAME: "displayOrder",
                    DATA_TYPE: "number",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('DisplayOrder'),
                    DISPLAY_ORDER: 6,
                }

            ],
            listheaderbuttons:
                [
                    {
                        title: 'AddNew',
                        iconClass: 'fa fa-plus',
                        callbackfunction: 'Add',
                        additionalClass: '',
                        isdisabled: false,
                        isvisible: true,
                        checkPrivilege: false,
                    },
                    {
                        title: 'Delete',
                        iconClass: 'fa fa-trash',
                        callbackfunction: 'Delete',
                        additionalClass: '',
                        isdisabled: true,
                        isvisible: true,
                        checkPrivilege: false,
                        isEnabledOnSelectedRow: true
                    },
                    {
                        title: 'BacktoList',
                        iconClass: 'fa fa-angle-double-left',
                        callbackfunction: 'BackToList',
                        additionalClass: '',
                        isdisabled: false,
                        isvisible: true,
                        checkPrivilege: false
                    }
                ],
            listActions: [
                {
                    title: 'Edit',
                    callbackfunction: 'EditRecord',
                    icon: 'fa fa-pencil text-success action-icon',
                    additionalSpan: '',
                    
                }
            ],
        }
    },
    async created() {
        var ths = this;
        await ths.FetchData();
    },
    methods: {
        CloseLimit() {
            this.EditLimitData = [];
            this.refCode = '';
            this.isAddLimit = false;
        },
        FetchData() {
            var vm = this;
            vm.isLoading = true;
            if (this.configurationId == null || this.configurationId == 0) {
                this.configurationId = 0;
            }
            var url = `configId=${vm.configurationId}&limitId=${vm.LimitId}&client_id=${this.clientId}&sort_by=${vm.Sort_By}sort_exp=${vm.Sort_Exp}&pagesize=${vm.PageSize}&pageNumber=${vm.PageNumber}`;
            DataService.GetLimitListing(url).then((response) => {
                if (response.data != '') {
                    if (response.data.length > 0) {
                        debugger;
                        vm.LimitData = response.data;
                        vm.TotalRecords = vm.LimitData.length > 0 ? vm.LimitData[0].totalRecords : 0;
                        vm.noRecord = false;
                        if (this.mode === 'View') {
                            vm.listheaderbuttons[0].isvisible = false;
                            vm.listheaderbuttons[1].isvisible = false;
                            vm.isShowCheckBox =false;
                        }
                    }
                }
                else {
                    vm.LimitData = [];
                    vm.TotalRecords = 0;
                    vm.noRecord = true;
                }
            });
            vm.isLoading = false;
        },

        renderActions(row) {
            let rtnActionArray = [];
            this.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                if (this.mode === 'View') {
                    action.isVisible = false;
                } else {
                    action.isVisible = true;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        actionButtonClick(callbackfunction, item, index, event, isChild) {
            switch (callbackfunction) {
                case 'EditRecord':
                    this.EditLimit(item);
                    break;
            }
        },
        EditLimit(item) {
            var vm = this;
            var privilegeParams = `controller=BillingRule&action=EditBillingLimit`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            vm.EditLimitData = item;
            vm.refCode = 'Update';
            vm.isAddLimit = true;
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        commonHeaderButtonClick(event) {
            switch (event.callbackfunction) {
                case "Add":
                    this.AddLimitRecord();
                    break;
                case "BackToList":
                    this.BackToList();
                    break;
                case "Delete":
                    this.commonDeleteData();
            }
        },
        commonDeleteData: function (event) {
            var vm = this;
            var val = "";

            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(async function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                var privilegeParams = `controller=BillingRule&action=DeleteLimit`;
                DataService.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("LimitValue")), function () {
                    var postJSON = {
                        ids: val,
                        moduleName: "BillingRule",
                        refCode: "TALYGEN_BE_billing_limits"
                    };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.CommonCommonDelete(objectPostString).then(async function (response) {
                        if (response.status == 200) {
                            $('.chkItems:checkbox:checked,#chkAll_0').prop("checked", false).removeAttr('checked');
                            $("#DeleteMultiple").addClass("disabled");
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('LimitValue')]), "success", true, vm.$t("Alert"));
                            vm.FetchData();
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('LimitValue')]), "failure", true, vm.$t("Alert"));
                        }

                    });

                });
                vm.FetchData();
                 }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "failure", true, vm.$t("Alert"));
            }

        },
        BackToList() {
            var vm = this;
            vm.$router.push({name: vm.isBillingType ? 'BillingRule' : 'BillingRuleListing'});
        },
        AddLimitRecord() {
            var privilegeParams = `controller=BillingRule&action=AddBillingLimit`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            this.isAddLimit = true;
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        pagerMethod(value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        sortdata: function (SortBy) {
            this.SortBy = SortBy;
            var SortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                SortExp = 'DESC';
            }
            this.SortExp = SortExp;
            this.SortBy = SortBy;
            this.SortExp = SortExp;
            this.PageNumber = 1;
            this.GroupStart = this.PageNumber;
            this.GroupEnd = this.PageNumber + 2;
            this.FetchData();
        },
        leftCommonSearch: async function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (value.searchCondition != "" && typeof value.searchCondition != 'undefined') {
                let str = value.searchConditionJson;
                const regex = /(WORK_CODE|WORK_CODE_CATEGORY_ID)\s*(?:LIKE\s+'?%?|=)\s*([^%')\s]+).*?/i;
                const m = str.match(regex);
                const column = m[1];
                const values = m[2];
                switch (column) {
                    case "WORK_CODE":
                        this.searchCondition = values;
                        break;
                    case "WORK_CODE_CATEGORY_ID":
                        this.categoryId = values;
                        break;
                }
            }
            else {
                this.categoryId = "";
                this.searchCondition = "";
            }
            this.FetchData();
        }
    },

}


</script>

<style lang="scss" scoped></style>